const dialog=document.getElementById("menuDialog"),menuList=document.getElementById("menuList"),menuIcon=document.querySelector(".nav-icon");function menuShow(){menuIcon.classList.add("active"),dialog.addEventListener("click",()=>magicClose()),dialog.inert=!0,dialog.showModal(),dialog.inert=!1,menuList.addEventListener("click",e=>e.stopPropagation())}function magicClose(){if(menuIcon.classList.remove("active"),cantAnimate){dialog.close();return}dialog.classList.add("hide"),dialog.addEventListener("webkitAnimationEnd",function(){dialog.classList.remove("hide"),dialog.close(),dialog.removeEventListener("webkitAnimationEnd",arguments.callee,!1)},!1)}